1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
17	type Step = { op: "quote"; items: Item[] };
18	type Scenario = { customer: unknown; steps: Step[] };
19	
20	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
21	
22	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
23	
24	const groupByType = (items: Item[]): Map<string, number> =>
25	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
26	
27	const componentGroupPremium = (type: string, count: number): number =>
28	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
29	
30	const componentsPremium = (items: Item[]): number =>
31	  Array.from(groupByType(items.filter(isComponent)))
32	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
33	
34	const itemPremium = (item: Item): number => {
35	  const base = basePremiumFor(item.type);
36	  return item.cursed ? base * 1.5 : base;
37	};
38	
39	const mainItemsPremium = (items: Item[]): number =>
40	  items.filter((item) => !isComponent(item))
41	    .reduce((sum, item) => sum + itemPremium(item), 0);
42	
43	const itemsPremium = (items: Item[]): number =>
44	  mainItemsPremium(items) + componentsPremium(items);
45	
46	const quote = ({ items }: Step): { premium: number } => ({
47	  premium: itemsPremium(items) + PROCESSING_FEE,
48	});
49	
50	export const runScenario = (input: unknown): unknown => {
51	  const { steps } = input as Scenario;
52	  return { results: steps.map(quote) };
53	};
